export type { CloudflareAccessBindings } from "./config";
export { CloudflareAccessConfig, makeCloudflareAccessConfig } from "./config";
export {
  AuthErrorResponse,
  CloudflareAccessInvalidError,
  CloudflareAccessMisconfiguredError,
  CloudflareAccessRequiredError,
  CloudflareAccessUnsupportedIdentityError,
  toCloudflareAccessAuthErrorResponse,
  type CloudflareAccessAuthError,
} from "./errors";
export { CloudflareAccessKeyResolver, type AccessKeyResolver } from "./key-resolver";
export { CloudflareAccessJwtVerifier, verifyAccessJwt } from "./jwt";
export { CurrentCloudflareAccessPrincipal, RequireCloudflareAccess } from "./middleware";
export {
  CloudflareAccessEmail,
  CloudflareAccessServiceTokenClientId,
  normalizeCloudflareAccessPrincipal,
  type CloudflareAccessPrincipal,
} from "./principal";

import { Context, Effect, Layer } from "effect";

import { CloudflareAccessMisconfiguredError } from "./errors";

/**
 * Worker env bindings required for Cloudflare Access verification.
 */
export interface CloudflareAccessBindings {
  CLOUDFLARE_ACCESS_TEAM_DOMAIN: string;
  CLOUDFLARE_ACCESS_AUD: string;
}

/**
 * Effect service carrying normalized Cloudflare Access verifier configuration.
 */
export class CloudflareAccessConfig extends Context.Service<
  CloudflareAccessConfig,
  {
    readonly teamDomain: string;
    readonly audience: string;
  }
>()("@mulroy/cloudflare-access/CloudflareAccessConfig") {
  /**
   * Builds normalized Cloudflare Access config from Worker environment bindings.
   *
   * @param env Worker environment bindings containing the Access team domain and audience.
   * @returns An Effect that succeeds with normalized config or fails when the bindings are invalid.
   */
  static readonly fromEnv = (env: CloudflareAccessBindings) =>
    makeCloudflareAccessConfig({
      teamDomain: env.CLOUDFLARE_ACCESS_TEAM_DOMAIN,
      audience: env.CLOUDFLARE_ACCESS_AUD,
    });

  /**
   * Builds a layer that provides Cloudflare Access config from Worker environment bindings.
   *
   * @param env Worker environment bindings containing the Access team domain and audience.
   * @returns A layer that provides `CloudflareAccessConfig`.
   */
  static readonly layerFromEnv = (env: CloudflareAccessBindings) =>
    Layer.effect(CloudflareAccessConfig, CloudflareAccessConfig.fromEnv(env));

  /**
   * Builds a layer from already-normalized Cloudflare Access config.
   *
   * @param config Normalized Cloudflare Access config.
   * @returns A layer that provides `CloudflareAccessConfig`.
   */
  static readonly layer = (config: Context.Service.Shape<typeof CloudflareAccessConfig>) =>
    Layer.succeed(CloudflareAccessConfig, config);
}

/**
 * Normalizes and validates Cloudflare Access verifier configuration.
 *
 * @param input Raw Cloudflare Access team domain and audience values.
 * @returns An Effect that succeeds with normalized config or fails with `CloudflareAccessMisconfiguredError`.
 */
export const makeCloudflareAccessConfig = Effect.fn("makeCloudflareAccessConfig")(
  function* (input: {
    readonly teamDomain: string;
    readonly audience: string;
  }): Effect.fn.Return<
    Context.Service.Shape<typeof CloudflareAccessConfig>,
    CloudflareAccessMisconfiguredError
  > {
    const teamDomainInput = input.teamDomain.trim().replace(/\/+$/, "");
    const audience = input.audience.trim();

    if (teamDomainInput.length === 0 || audience.length === 0) {
      return yield* new CloudflareAccessMisconfiguredError();
    }

    let url: URL;
    try {
      url = new URL(teamDomainInput);
    } catch (cause) {
      return yield* new CloudflareAccessMisconfiguredError({ cause });
    }

    if (url.protocol !== "https:") {
      return yield* new CloudflareAccessMisconfiguredError();
    }

    return CloudflareAccessConfig.of({
      teamDomain: url.toString().replace(/\/+$/, ""),
      audience,
    });
  },
);

import { Schema } from "effect";

const CloudflareAccessRequiredErrorResponse = Schema.Struct({
  error: Schema.Literal("cloudflare_access_required"),
  message: Schema.String,
}).annotate({ httpApiStatus: 403 });
const CloudflareAccessInvalidErrorResponse = Schema.Struct({
  error: Schema.Literal("cloudflare_access_invalid"),
  message: Schema.String,
}).annotate({ httpApiStatus: 403 });
const CloudflareAccessUnsupportedIdentityErrorResponse = Schema.Struct({
  error: Schema.Literal("cloudflare_access_unsupported_identity"),
  message: Schema.String,
}).annotate({ httpApiStatus: 403 });
const CloudflareAccessMisconfiguredErrorResponse = Schema.Struct({
  error: Schema.Literal("cloudflare_access_misconfigured"),
  message: Schema.String,
}).annotate({ httpApiStatus: 500 });

/**
 * Schema variants for HTTP responses emitted by Cloudflare Access middleware.
 */
export const CloudflareAccessHttpErrorResponses = [
  CloudflareAccessRequiredErrorResponse,
  CloudflareAccessInvalidErrorResponse,
  CloudflareAccessUnsupportedIdentityErrorResponse,
  CloudflareAccessMisconfiguredErrorResponse,
] as const;

/**
 * Schema for serialized Cloudflare Access auth error responses.
 */
export const AuthErrorResponse = Schema.Union(CloudflareAccessHttpErrorResponses);

/**
 * Serialized Cloudflare Access auth error response body.
 */
export type AuthErrorResponse = typeof AuthErrorResponse.Type;

/**
 * Error returned when a request does not include a Cloudflare Access JWT.
 */
export class CloudflareAccessRequiredError extends Schema.TaggedErrorClass<CloudflareAccessRequiredError>()(
  "CloudflareAccessRequiredError",
  {
    error: Schema.Literal("cloudflare_access_required"),
    message: Schema.String,
    status: Schema.Literal(403),
  },
  { httpApiStatus: 403 },
) {
  /**
   * Creates a missing-token Cloudflare Access error.
   */
  constructor() {
    super({
      error: "cloudflare_access_required",
      message: "Cloudflare Access JWT is required.",
      status: 403,
    });
  }
}

/**
 * Error returned when a Cloudflare Access JWT cannot be verified or decoded.
 */
export class CloudflareAccessInvalidError extends Schema.TaggedErrorClass<CloudflareAccessInvalidError>()(
  "CloudflareAccessInvalidError",
  {
    error: Schema.Literal("cloudflare_access_invalid"),
    message: Schema.String,
    status: Schema.Literal(403),
    cause: Schema.optionalKey(Schema.Defect),
  },
  { httpApiStatus: 403 },
) {
  /**
   * Creates an invalid-JWT Cloudflare Access error.
   *
   * @param args Optional cause captured from JWT verification or payload decoding.
   */
  constructor(args: { readonly cause?: unknown } = {}) {
    super({
      error: "cloudflare_access_invalid",
      message: "Cloudflare Access JWT is invalid.",
      status: 403,
      cause: args.cause,
    });
  }
}

/**
 * Error returned when verified Access claims do not identify exactly one supported principal type.
 */
export class CloudflareAccessUnsupportedIdentityError extends Schema.TaggedErrorClass<CloudflareAccessUnsupportedIdentityError>()(
  "CloudflareAccessUnsupportedIdentityError",
  {
    error: Schema.Literal("cloudflare_access_unsupported_identity"),
    message: Schema.String,
    status: Schema.Literal(403),
    cause: Schema.optionalKey(Schema.Defect),
  },
  { httpApiStatus: 403 },
) {
  /**
   * Creates an unsupported-identity Cloudflare Access error.
   *
   * @param args Optional cause captured from principal claim decoding.
   */
  constructor(args: { readonly cause?: unknown } = {}) {
    super({
      error: "cloudflare_access_unsupported_identity",
      message: "Cloudflare Access identity is unsupported.",
      status: 403,
      cause: args.cause,
    });
  }
}

/**
 * Error returned when Cloudflare Access verifier configuration is invalid.
 */
export class CloudflareAccessMisconfiguredError extends Schema.TaggedErrorClass<CloudflareAccessMisconfiguredError>()(
  "CloudflareAccessMisconfiguredError",
  {
    error: Schema.Literal("cloudflare_access_misconfigured"),
    message: Schema.String,
    status: Schema.Literal(500),
    cause: Schema.optionalKey(Schema.Defect),
  },
  { httpApiStatus: 500 },
) {
  /**
   * Creates a Cloudflare Access configuration error.
   *
   * @param args Optional cause captured while parsing configuration or JWKS URLs.
   */
  constructor(args: { readonly cause?: unknown } = {}) {
    super({
      error: "cloudflare_access_misconfigured",
      message: "Cloudflare Access is misconfigured.",
      status: 500,
      cause: args.cause,
    });
  }
}

/**
 * Typed errors produced by Cloudflare Access authentication checks.
 */
export type CloudflareAccessAuthError =
  | CloudflareAccessRequiredError
  | CloudflareAccessInvalidError
  | CloudflareAccessUnsupportedIdentityError;

/**
 * Converts a typed Cloudflare Access error into its public HTTP response body.
 *
 * @param error Cloudflare Access auth or configuration error.
 * @returns Public error response body.
 */
export function toCloudflareAccessAuthErrorResponse(
  error: CloudflareAccessAuthError | CloudflareAccessMisconfiguredError,
): AuthErrorResponse {
  return { error: error.error, message: error.message };
}
